mapper.select:
select d.id as documentId, d.group_id as groupId, d.file_name as fileName, d.file_ext as fileExt, d.content_type as contentType, d.file_size as fileSize, d.status as status, d.failure_reason as failureReason, d.uploaded_at as uploadedAt, d.uploader_user_id as uploaderUserId, u.user_code as uploaderUserCode, u.display_name as uploaderDisplayName, d.preview_text as previewText from documents d inner join users u on u.id = d.uploader_user_id inner join groups g on g.id = d.group_id inner join group_memberships gm on gm.group_id = d.group_id where d.deleted = false and g.status = 'ACTIVE' and gm.user_id = #{currentUserId}
and d.group_id = #{groupId}
and gm.role = 'OWNER'
and gm.role = 'MEMBER'
and d.file_name like concat('%', #{fileName}, '%')
and d.uploader_user_id = #{uploaderUserId}
and d.status = #{status}
and d.uploaded_at >= #{uploadedFrom}
and d.uploaded_at <= #{uploadedTo}
order by d.uploaded_at desc, d.id desc

mapper.update:
update documents
set deleted = true,
    updated_at = now()
where id = #{documentId}
  and group_id = #{groupId}
  and deleted = false
